import{_ as t,c as o,o as a,ag as i}from"./chunks/framework.DPDPlp3K.js";const r="/assets/contextual_help.o5s4no2y.gif",g=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1773349399000}'),s={name:"index.md"};function n(l,e,u,h,d,c){return a(),o("div",null,e[0]||(e[0]=[i('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">ŌĆŗ</a></h1><p>Reviewable is a comprehensive code review tool that is fully integrated with GitHub (and only GitHub). It&#39;s</p><ul><li><strong>Thorough</strong> ŌĆö Tracks where par┬Łtic┬Łi┬Łpants stand on each dis┬Łcus┬Łsion, en┬Łsur┬Łing it won&#39;t dis┬Łap┬Łpear un┬Łtil re┬Łsolved. Fully cus┬Łtomiz┬Łable logic de┬Łter┬Łmines when a re┬Łview is com┬Łplete.</li><li><strong>Efficient</strong> ŌĆö Clearly shows net deltas since last time you looked, even if com┬Łmits get re┬Łbased or amended. Batches com┬Łments and cor┬Łrectly threads email re┬Łsponses.</li><li><strong>Fo┬Łcused</strong> ŌĆö Works only with GitHub and GitHub En┬Łter┬Łprise, mak┬Łing for a seam┬Łless in┬Łte┬Łgra┬Łtion. Min┬Łi┬Łmal ad┬Łmin busy┬Łwork, no ex┬Łtra fluff ŌĆö just awe┬Łsome code re┬Łviews.</li></ul><p>With Reviewable, you can:</p><ul><li>In┬Łstantly diff any two re┬Łvi┬Łsions of a file, in either a uni┬Łfied or side-by-side view.</li><li>Hide mi┬Łnor changes, including white┬Łspace, merge, and re┬Łbase deltas.</li><li>Map line com┬Łments across file re┬Łvi┬Łsions and keep them around un┬Łtil re┬Łsolved, not just un┬Łtil changes are pushed.</li><li>Keep track of who re┬Łviewed which re┬Łvi┬Łsion of each file to ensure that no changes are missed.</li><li>Com┬Łbine com┬Łmits for review, or re┬Łview each commit separately.</li><li>Cus┬Łtomize the line length mar┬Łgin, fonts, col┬Łors, key┬Łboard short┬Łcuts, and more.</li><li>Jump from a com┬Łment straight to the right spot in your fa┬Łvorite ed┬Łi┬Łtor.</li><li>Enjoy a mod┬Łern, clean UI with a touch of whimsy.</li><li>Get full con┬Łtex┬Łtual help, and fast sup┬Łport if you have ques┬Łtions.</li><li>Sign in with GitHub ac┬Łcount ŌĆö no sep┬Ła┬Łrate ac┬Łcounts to man┬Łage.</li><li>Keep all your code on GitHub, not on our servers.</li></ul><p>This user guide is a helpful resource for learning all of the details about every Reviewable feature. Once you understand the basics, you&#39;ll be more efficient at eliminating buggy code and helping your team improve their delivery pipeline.</p><h2 id="how-to-use-this-guide" tabindex="-1">How to use this guide <a class="header-anchor" href="#how-to-use-this-guide" aria-label="Permalink to &quot;How to use this guide&quot;">ŌĆŗ</a></h2><p>Reviewable is a powerful, feature-rich, and highly configurable tool. It&#39;s easy to get started, and its full potential will become clearer as you go. The first steps are fairly straightforward:</p><ol><li>Everybody should read through the <a href="./registration">Registration and GitHub Authorization</a> section that follows.</li><li>Then, if Reviewable is already set up for your favorite repos, you can just keep reading straight into the <a href="./reviews">Code review</a> section that follows and dip into the other sections as needed.</li><li>If, on the other hand, you&#39;re an admin setting up Reviewable for the first time, you&#39;ll want to jump to the <a href="./admincenter">Admin Center</a> section first for details on how to connect repos and start a subscription (if necessary).</li></ol><p>If at any point you notice a typo or mistake, please don&#39;t hesitate to jump in and propose an edit via the link in the top right corner of every page.</p><h2 id="help-on-using-reviewable" tabindex="-1">Help on using Reviewable <a class="header-anchor" href="#help-on-using-reviewable" aria-label="Permalink to &quot;Help on using Reviewable&quot;">ŌĆŗ</a></h2><p>Help is available through many channels:</p><ul><li>Contextual Help: Press <code>F1</code> or <code>h</code>, or click <strong>Support &gt; Help</strong>, to view the hints for all of the features on a page. If you invoke help while hovering your mouse pointer over a button or feature, specific help for that feature will appear. Press the same key again, press Esc, or click on the grey background to get back to the app.</li></ul><p><img src="'+r+'" alt="contextual help demo"></p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>On tablets and other touch devices with no convenient keyboard, tap the question mark icon in the bottom-right corner of the screen instead.</p></div><ul><li><p>Chat: Click <strong>Support &gt; Chat</strong> to chat with our team. We don&#39;t have access to what you&#39;re seeing unless you send us a screenshot.</p></li><li><p>Bug reports or feature requests: Click <strong>Support &gt; Issues</strong> to report a bug, or make a feature request. To potentially get an answer faster and help reduce triaging overhead, please check existing issues for duplicates first.</p></li><li><p><a href="mailto:support@reviewable.io" target="_blank" rel="noreferrer">Send us an email</a> for questions that should stay private. If you&#39;re an Enterprise user, you can chat with us in our shared chat channel (Slack, Teams, etc).</p></li></ul><h2 id="staying-up-to-date" tabindex="-1">Staying up to date <a class="header-anchor" href="#staying-up-to-date" aria-label="Permalink to &quot;Staying up to date&quot;">ŌĆŗ</a></h2><p>The changelog (<strong>Support &gt; Changelog</strong>) always has the latest on features and bug fixes. Check out our <a href="https://www.reviewable.io/blog/" target="_blank" rel="noreferrer">blog</a> for feature deep dives and developer stories. For the truly dedicated, you can watch the <a href="https://github.com/reviewable/reviewable" target="_blank" rel="noreferrer">Reviewable/Reviewable</a> repo for new issues and updates to these docs.</p>',18)]))}const f=t(s,[["render",n]]);export{g as __pageData,f as default};
